const input = $json.body?.chatInput || $json.chatInput || '';
const sessionId = $json.body?.sessionId || $json.sessionId || '';
const slug = $json.body?.slug || $json.slug || '';
const groqApiKey = $json.body?.groqApiKey || $json.groqApiKey || '';

if (input.length > 2000) {
  return [{ json: { blocked: true, output: 'Please keep your message under 2000 characters.', sessionId, slug, groqApiKey }}];
}

const injectionPatterns = [
  /ignore\s+(all\s+)?(previous|above|prior)\s+(instructions?|prompts?|rules?)/i,
  /you\s+are\s+now\s+(a|an|the)/i,
  /new\s+(role|instructions?|system)\s*:/i,
  /act\s+as\s+if\s+you\s+have\s+no\s+(rules?|restrictions?)/i,
  /pretend\s+you\s+are/i,
  /disable\s+(your\s+)?(safety|filters?|guardrails?)/i,
  /\bDAN\b|\bjailbreak\b|\bdeveloper\s+mode\b/i,
  /system\s*:\s*/i,
  /\[INST\]|<<?SYS>>?/i,
  /how\s+do\s+I\s+(hack|exploit|bypass)/i,
  /what\s+(are|is)\s+your\s+(system\s+)?(prompt|instructions?)/i,
  /reveal\s+(your|the)\s+(system|original)\s+prompt/i,
  /repeat\s+(everything|all|the)\s+(above|before)/i,
];

for (const pattern of injectionPatterns) {
  if (pattern.test(input)) {
    return [{ json: { blocked: true, output: 'I can only help with portfolio-related questions. What would you like to know about my work?', sessionId, slug, groqApiKey }}];
  }
}

if (/(.)\1{10,}/.test(input)) {
  return [{ json: { blocked: true, output: 'Looks like something went wrong. Try typing a real question!', sessionId, slug, groqApiKey }}];
}

if (input.trim().length === 0) {
  return [{ json: { blocked: true, output: 'Ask me about my work or book a meeting!', sessionId, slug, groqApiKey }}];
}

return [{ json: { blocked: false, chatInput: input, sessionId, slug, groqApiKey }}];

const slug = $json.slug || 'default';
const sessionId = $json.sessionId;
const chatInput = $json.chatInput;
const groqApiKey = $json.groqApiKey;
const baseUrl = 'http://api:3000/api/widget/' + slug;

try {
  const [profile, projects, services, faq, config] = await Promise.all([
    this.helpers.httpRequest({ method: 'GET', url: baseUrl + '/profile' }).catch(() => ({})),
    this.helpers.httpRequest({ method: 'GET', url: baseUrl + '/projects' }).catch(() => []),
    this.helpers.httpRequest({ method: 'GET', url: baseUrl + '/services' }).catch(() => []),
    this.helpers.httpRequest({ method: 'GET', url: baseUrl + '/faq' }).catch(() => []),
    this.helpers.httpRequest({ method: 'GET', url: baseUrl + '/config' }).catch(() => ({})),
  ]);
  return [{ json: { slug, sessionId, chatInput, groqApiKey, profileData: profile, projectsData: projects, servicesData: services, faqData: faq, widgetConfig: config }}];
} catch (e) {
  return [{ json: { slug, sessionId, chatInput, groqApiKey, profileData: {}, projectsData: [], servicesData: [], faqData: [], widgetConfig: {} }}];
}

const { chatInput, systemPrompt, sessionId, slug, groqApiKey } = $json;
const groqKey = groqApiKey || process.env.GROQ_API_KEY || '';
if (!groqKey) {
  return [{ json: { output: 'Groq API key is not configured. Please set GROQ_API_KEY in environment.', sessionId, slug }}];
}

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.groq.com/openai/v1/chat/completions',
  headers: {
    'Authorization': 'Bearer ' + groqKey,
    'Content-Type': 'application/json',
  },
  body: {
    model: 'llama-3.3-70b-versatile',
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: chatInput },
    ],
    temperature: 0.7,
    max_tokens: 500,
  },
  json: true,
});

const output = response.choices[0].message.content;
return [{ json: { output, sessionId, slug }}];

const output = $json.output || '';
let cleanOutput = output.length > 1000 ? output.substring(0, 997) + '...' : output;

const leakPatterns = [
  /sk-[a-zA-Z0-9]{20,}/,
  /ghp_[a-zA-Z0-9]{36}/,
  /password\s*[:=]\s*\S+/i,
  /secret\s*[:=]\s*\S+/i,
  /localhost:\d+/,
  /127\.0\.0\.1/,
  /192\.168\./,
  /10\.0\./,
  /http:\/\/n8n/,
  /https?:\/\/.*\.n8n\./,
  /n8n:5678/,
  /api\.groq\.com/,
  /api\.openai\.com/,
];

for (const pattern of leakPatterns) {
  if (pattern.test(cleanOutput)) {
    cleanOutput = "I can only answer portfolio-related questions about Abdullah's skills, projects, services, or meeting booking.";
    break;
  }
}

const promptLeakPatterns = [
  /my\s+(system\s+)?(prompt|instructions?)\s+(is|are|says)/i,
  /I\s+(was|am)\s+(told|instructed|programmed)\s+to/i,
  /according\s+to\s+my\s+(rules?|instructions?)/i,
];

for (const pattern of promptLeakPatterns) {
  if (pattern.test(cleanOutput)) {
    cleanOutput = "I can only answer portfolio-related questions about Abdullah's skills, projects, services, or meeting booking.";
    break;
  }
}

return [{ json: { output: cleanOutput, sessionId: $json.sessionId }}];
